mapper.select:
SELECT d.*, ma.area_name
FROM hf_device d
LEFT JOIN hf_monitor_area ma ON d.area_id = ma.id
WHERE d.is_deleted = 0

    AND d.device_id LIKE CONCAT('%', #{query.deviceId}, '%')


    AND d.device_name LIKE CONCAT('%', #{query.deviceName}, '%')


    AND d.device_type = #{query.deviceType}


    AND d.area_id = #{query.areaId}


    AND d.status = #{query.status}

ORDER BY d.create_time DESC
